# Server Script (DocType Event) - Sales Order - After Save
# Auto-share Sales Order with users linked to Sales Person (and parent Sales Persons).
# NOTE: Avoids safe_exec-restricted attributes like frappe.db.commit() and frappe.get_traceback().

try:
    sales_persons = [r.sales_person for r in (doc.get("sales_team") or []) if r.get("sales_person")]

    if sales_persons:
        # include parent_sales_person(s) if any
        parent_rows = frappe.get_all(
            "Sales Person",
            filters={"name": ["in", sales_persons]},
            fields=["parent_sales_person"]
        )
        all_sps = set(sales_persons)
        for r in parent_rows:
            p = r.get("parent_sales_person")
            if p:
                all_sps.add(p)

        # get users with User Permission for these Sales Persons
        user_perms = frappe.get_all(
            "User Permission",
            filters={
                "allow": "Sales Person",
                "for_value": ["in", list(all_sps)]
            },
            fields=["user"]
        )
        users = {u["user"] for u in user_perms}

        shared_users = []
        for user in users:
            # skip if already shared
            existing = frappe.get_all(
                "DocShare",
                filters={
                    "user": user,
                    "share_doctype": doc.doctype,
                    "share_name": doc.name
                },
                fields=["name"],
                limit_page_length=1
            )
            if existing:
                continue

            try:
                # preferred helper (if available)
                try:
                    frappe.share.add(user, doc.doctype, doc.name,
                                     permlevel=0, read=1, write=1, submit=1, share=1)
                except Exception as e_share:
                    # fallback: insert DocShare directly (ignore permissions)
                    ds = frappe.get_doc({
                        "doctype": "DocShare",
                        "user": user,
                        "share_doctype": doc.doctype,
                        "share_name": doc.name,
                        "read": 1,
                        "write": 1,
                        "submit": 1,
                        "share": 1
                    })
                    ds.insert(ignore_permissions=True)

                shared_users.append(user)

            except Exception as e:
                # safe logging inside Server Script sandbox: use string form of exception
                frappe.log_error(title="sales_order_share: failed for user " + str(user),
                                 message=str(e))

        # Note: committing from Server Script is restricted in safe_exec; workspace will commit with normal save flow.
        # We avoid calling frappe.db.commit() here.

except Exception as e_outer:
    frappe.log_error(title="sales_order_share: unexpected error", message=str(e_outer))

if doc.currency == doc.price_list_currency:
	if doc.conversion_rate and doc.plc_conversion_rate:
	    if doc.conversion_rate != doc.plc_conversion_rate:
	        doc.plc_conversion_rate = doc.conversion_rate
	        #frappe.throw("Exchange rate and price list exchange rate should be the same!")
	    else:
	    	company_default_currency = frappe.db.get_value("Company", doc.company, "default_currency")
	    	entries = frappe.get_all("Currency Exchange", fields=["exchange_rate"], filters=[["date", "<=", frappe.utils.get_datetime_str(doc.transaction_date)],["from_currency", "=", doc.currency],["to_currency", "=", company_default_currency]], order_by="date desc", limit=1)
	    	if entries:
	    	    exc_rate = frappe.utils.flt(entries[0].exchange_rate)
	    	if (exc_rate != doc.conversion_rate) or (exc_rate != doc.plc_conversion_rate):
	    		frappe.throw("Exchange rate is wrong!")

if doc.currency == doc.price_list_currency:
    if doc.conversion_rate and doc.plc_conversion_rate:

        if doc.conversion_rate != doc.plc_conversion_rate:
            doc.plc_conversion_rate = doc.conversion_rate

        else:
            company_default_currency = frappe.db.get_value(
                "Company", doc.company, "default_currency"
            )

            exc_rate = None
            entries = frappe.get_all(
                "Currency Exchange",
                fields=["exchange_rate"],
                filters=[
                    ["date", "<=", frappe.utils.get_datetime_str(doc.transaction_date)],
                    ["from_currency", "=", doc.currency],
                    ["to_currency", "=", company_default_currency],
                ],
                order_by="date desc",
                limit=1,
            )

            if entries:
                exc_rate = frappe.utils.flt(entries[0].exchange_rate)

            if exc_rate is None:
                frappe.msgprint(
                    f"No Currency Exchange rate found for {doc.currency} → {company_default_currency} "
                    f"on or before {doc.transaction_date}",
                    indicator="orange"
                )

            else:
                if abs(exc_rate - doc.conversion_rate) > 0.000001 or abs(exc_rate - doc.plc_conversion_rate) > 0.000001:
                    frappe.msgprint(
                        "⚠ Exchange rate does not match the system rate. Please review.",
                        indicator="orange"
                    )

