async function shareSalesOrderWithUsers(frm) {
    if (!frm.doc.sales_team || frm.doc.sales_team.length === 0) return;

    // Step 1: Collect all sales_persons from sales_team
    const salesPersons = frm.doc.sales_team
        .map(row => row.sales_person)
        .filter(Boolean);

    if (salesPersons.length === 0) return;

    let allSalesPersons = new Set(salesPersons);

    // Step 2: Fetch parent_sales_person for each sales_person
    await Promise.all(salesPersons.map(sp => {
        return frappe.db.get_value('Sales Person', sp, 'parent_sales_person')
            .then(res => {
                if (res?.message?.parent_sales_person) {
                    allSalesPersons.add(res.message.parent_sales_person);
                }
            });
    }));

    // Step 3: Fetch users with User Permission for these Sales Persons
    frappe.call({
        method: "frappe.client.get_list",
        args: {
            doctype: "User Permission",
            filters: {
                allow: "Sales Person",
                for_value: ["in", Array.from(allSalesPersons)]
            },
            fields: ["user"],
            limit_page_length: 100
        },
        callback: function(res) {
            if (!res.message || res.message.length === 0) return;

            const users = [...new Set(res.message.map(r => r.user))];

            // Step 4: For each user, check if DocShare exists before inserting
            users.forEach(user => {
                frappe.call({
                    method: "frappe.client.get_list",
                    args: {
                        doctype: "DocShare",
                        filters: {
                            user: user,
                            share_doctype: frm.doc.doctype,
                            share_name: frm.doc.name
                        },
                        limit_page_length: 1
                    },
                    callback: function(res) {
                        if (res.message && res.message.length > 0) {
                            console.log(`Already shared with user: ${user}`);
                        } else {
                            // Step 5: Share Sales Order with user (read + write)
                            frappe.call({
                                method: "frappe.client.insert",
                                args: {
                                    doc: {
                                        doctype: "DocShare",
                                        user: user,
                                        share_doctype: frm.doc.doctype,
                                        share_name: frm.doc.name,
                                        read: 1,
                                        write: 1,
                                        share: 1,
                                        submit: 1
                                    }
                                },
                                callback: function() {
                                    console.log(`Shared with user: ${user}`);
                                }
                            });
                        }
                    }
                });
            });
        }
    });
}


