let discount_timer = null;

frappe.ui.form.on('Sales Order', {
    discount_amount: function(frm) {
        if (frm.doc.apply_discount_on !== "Net Total") {
            frappe.throw("❌ Discount is only allowed when 'Apply Discount On' is set to <b>Net Total</b>.");
            return;
        }

        if (discount_timer) clearTimeout(discount_timer);

        discount_timer = setTimeout(() => {
            let total = parseFloat(frm.doc.total) || 0;
            let discount = parseFloat(frm.doc.discount_amount) || 0;

            if (discount > 0 && total > 0) {
                let perc = (discount / total) * 100;
                console.log(`🎯 Calculated Discount %: ${perc.toFixed(6)}`);
                frm.set_value('additional_discount_percentage', parseFloat(perc.toFixed(6)));
            }
        }, 1000);
    },

    additional_discount_percentage: function(frm) {
        if (frm.doc.apply_discount_on !== "Net Total") {
            frappe.throw("❌ Discount is only allowed when 'Apply Discount On' is set to <b>Net Total</b>.");
            return;
        }

        let total = parseFloat(frm.doc.total) || 0;
        let perc = parseFloat(frm.doc.additional_discount_percentage) || 0;

        if (perc > 0 && total > 0) {
            let amt = (perc / 100) * total;
            console.log(`🎯 Calculated Discount Amount: ${amt.toFixed(2)}`);
            frm.set_value('discount_amount', parseFloat(amt.toFixed(2)));
        }
    }
});

