let _button_observer = null;

function apply_button_control(frm) {
    const internal_suppliers = [
        "INT-S005", "SUP-2025-00004", "INT-S004",
        "INT-S002", "INT-S001", "INT-S003"
    ];

    const isInternalSupplier = internal_suppliers.includes(frm.doc.supplier);
    const isDraft             = frm.doc.docstatus === 0;
    const isCancelled         = frm.doc.docstatus === 2;
    const isAllowedState      = [
        "Approved for Update",
        "Sent for Revision",
        "Pending Revise"
    ].includes(frm.doc.workflow_state);

    const shouldShowButtons = !isCancelled && (isDraft || isInternalSupplier || isAllowedState);
    const shouldShowStatus  = isAllowedState;

    const styleId = 'po-button-control-style';
    let styleEl = document.getElementById(styleId);
    if (!styleEl) {
        styleEl = document.createElement('style');
        styleEl.id = styleId;
        document.head.appendChild(styleEl);
    }

    const hiddenSelectors = [];
    if (!shouldShowButtons) {
        hiddenSelectors.push(
            '.page-actions button:contains-workaround-update-items',
            '.page-actions button:contains-workaround-get-items'
        );
    }
    if (!shouldShowStatus) {
        hiddenSelectors.push('.page-actions button:contains-workaround-status');
    }
    styleEl.textContent = '[data-po-hidden="true"] { display: none !important; }';

    function applyToButtons() {
        const wrapper = frm.page.wrapper;

        wrapper.find('button').each(function () {
            const $btn = $(this);
            const text = $btn.text().trim();

            if (text === 'Update Items' || text === 'Get Items From') {
                $btn.attr('data-po-hidden', shouldShowButtons ? null : 'true');
                $btn.attr('data-po-managed', 'true');
            } else if (text === 'Status') {
                $btn.attr('data-po-hidden', shouldShowStatus ? null : 'true');
                $btn.attr('data-po-managed', 'true');
            }
        });
    }

    applyToButtons();

    if (_button_observer) {
        _button_observer.disconnect();
        _button_observer = null;
    }

    const toolbar = frm.page.wrapper.find('.page-actions')[0];
    if (!toolbar) return;

    _button_observer = new MutationObserver((mutations) => {
        let relevant = false;
        for (const m of mutations) {
            if (m.type === 'childList' && m.addedNodes.length) {
                relevant = true;
                break;
            }
        }
        if (relevant) applyToButtons();
    });

    _button_observer.observe(toolbar, { childList: true, subtree: true });

    setTimeout(() => {
        if (_button_observer) {
            _button_observer.disconnect();
            _button_observer = null;
        }
    }, 5000);
}

